#include <ESP8266WiFi.h>
#include <ESP8266HTTPClient.h>

// WiFi credentials and API keys
const char* ssid = "YOUR_SSID";
const char* password = "YOUR_PASSWORD";
const char* apiKey = "YOUR_API_KEY";

void setup() {
  // Initialize serial for debugging
  Serial.begin(115200);
  
  // Connect to WiFi
  WiFi.mode(WIFI_STA);
  WiFi.begin(ssid, password);
  while (WiFi.status() != WL_CONNECTED) {
    delay(1000);
    Serial.println("Connecting to WiFi...");
  }
  
  // Print the IP address
  Serial.print("Connected with IP: ");
  Serial.println(WiFi.localIP());
}

void loop() {
  if (WiFi.status() == WL_CONNECTED) { // Check WiFi connection status
    HTTPClient http;  //Declare an object of class HTTPClient
  
    String serverPath = "http://iot-cloud-server/api/v1/devices"; //Specify request destination for ESP8266
    
    if (http.begin(serverPath)) {  //Start connection to the server
      http.addHeader("Content-Type", "application/json");   //Specify content-type header
      
      String payload = "{\"device_id\":\"ESP8266Camera\",\"ssid\":\""+String(ssid)+"\",\"ip\":\""+WiFi.localIP().toString()+"\"}";  //Data to send with the request
      
      int httpCode = http.POST(payload);    //Send the request
  
      if (httpCode > 0) { //Check for the returning code
        String response = http.getString();   //Get the response payload
        
        Serial.println("Response:");
        Serial.println(response);           //Print the response payload
      } else {
        Serial.printf("Error code: %d\n", httpCode);  //If server did not respond, print an error code
      }
  
      http.end();   //Close connection
    }
    
    delay(5000);    //Wait for 5 seconds before sending the next request
  }
}